def validate_string(value, field_name, max_length=1000, pattern=None, required=True):
    """Validate a string input."""
    if value is None or (isinstance(value, str) and value.strip() == ''):
        if required:
            raise ValueError(f"{field_name} is required")
        return None
    if not isinstance(value, str):
        raise ValueError(f"{field_name} must be a string")
    value = value.strip()
    if len(value) > max_length:
        raise ValueError(f"{field_name} exceeds maximum length of {max_length}")
    if pattern and not pattern.match(value):
        raise ValueError(f"{field_name} contains invalid characters")
    return value


def validate_object_id(value, field_name="id"):
    """Validate and convert a string to ObjectId."""
    if not isinstance(value, str):
        raise ValueError(f"{field_name} must be a string")
    try:
        return ObjectId(value)
    except InvalidId:
        raise ValueError(f"{field_name} is not a valid ID")


def validate_enum(value, allowed_values, field_name):
    """Validate that a value is in an allowlist."""
    if value not in allowed_values:
        raise ValueError(
            f"{field_name} must be one of: {', '.join(str(v) for v in allowed_values)}"
        )
    return value


def validate_integer(value, field_name, min_val=None, max_val=None):
    """Validate an integer input."""
    if not isinstance(value, int) or isinstance(value, bool):
        raise ValueError(f"{field_name} must be an integer")
    if min_val is not None and value < min_val:
        raise ValueError(f"{field_name} must be at least {min_val}")
    if max_val is not None and value > max_val:
        raise ValueError(f"{field_name} must be at most {max_val}")
    return value


def validate_tags(tags):
    """Validate a list of tags."""
    if not isinstance(tags, list):
        raise ValueError("Tags must be a list")
    if len(tags) > 20:
        raise ValueError("Maximum 20 tags allowed")
    validated = []
    tag_pattern = re.compile(r'^[a-zA-Z0-9_\- ]{1,50}$')
    for tag in tags:
        if not isinstance(tag, str):
            raise ValueError("Each tag must be a string")
        tag = tag.strip().lower()
        if not tag_pattern.match(tag):
            raise ValueError(f"Tag '{tag}' contains invalid characters")
        validated.append(tag)
    return validated


# --- Password Hashing ---

def hash_password(password):
    """Hash password with a random salt using SHA-256 (use bcrypt/argon2 in production)."""
    salt = secrets.token_hex(32)
    hashed = hashlib.pbkdf2_hmac('sha256', password.encode('utf-8'), salt.encode('utf-8'), 100000)
    return f"{salt}${hashed.hex()}"


def verify_password(password, stored_hash):
    """Verify a password against a stored hash."""
    try:
        salt, hash_hex = stored_hash.split('$')
        hashed = hashlib.pbkdf2_hmac('sha256', password.encode('utf-8'), salt.encode('utf-8'), 100000)
        return secrets.compare_digest(hashed.hex(), hash_hex)
    except (ValueError, AttributeError):
        return False


# --- JWT Token Management ---

def generate_token(user_id, username, role):
    """Generate a JWT token."""
    payload = {
        'user_id': str(user_id),
        'username': username,
        'role': role,
        'exp': datetime.utcnow() + timedelta(hours=JWT_EXPIRATION_HOURS),
        'iat': datetime.utcnow(),
        'jti': secrets.token_hex(16),
    }
    return jwt.encode(payload, JWT_SECRET, algorithm=JWT_ALGORITHM)


def decode_token(token):
    """Decode and validate a JWT token."""
    try:
        payload = jwt.decode(token, JWT_SECRET, algorithms=[JWT_ALGORITHM])
        return payload
    except jwt.ExpiredSignatureError:
        return None
    except jwt.InvalidTokenError:
        return None


# --- Authentication Decorator ---

def require_auth(f):
    """Decorator to require authentication."""
    @wraps(f)
    def decorated(*args, **kwargs):
        auth_header = request.headers.get('Authorization')
        if not auth_header or not auth_header.startswith('Bearer '):
            return jsonify({'error': 'Authentication required'}), 401

        token = auth_header.split(' ', 1)[1]
        payload = decode_token(token)
        if not payload:
            return jsonify({'error': 'Invalid or expired token'}), 401

        # Verify user still exists and is active
        try:
            user_id = validate_object_id(payload['user_id'], 'user_id')
        except ValueError:
            return jsonify({'error': 'Invalid token payload'}), 401

        user = users_collection.find_one(
            {'_id': user_id, 'active': True},
            {'password_hash': 0}
        )
        if not user:
            return jsonify({'error': 'User not found or inactive'}), 401

        g.current_user = user
        g.current_user_id = user['_id']
        g.current_role = payload.get('role', 'viewer')
        return f(*args, **kwargs)
    return decorated


def require_role(*roles):
    """Decorator to require specific roles."""
    def decorator(f):
        @wraps(f)
        def decorated(*args, **kwargs):
            if g.current_role not in roles:
                return jsonify({'error': 'Insufficient permissions'}), 403
            return f(*args, **kwargs)
        return decorated
    return decorator


