@app.route('/api/profiles/me', methods=['PUT'])
@require_auth
def update_my_profile():
    """Update the current user's profile."""
    try:
        data = request.get_json()
        if not data:
            return jsonify({'error': 'Request body is required'}), 400

        update_fields = {}

        if 'bio' in data:
            bio = validate_string(data['bio'], 'bio', max_length=500, required=False)
            update_fields['bio'] = bio or ''

        if 'display_name' in data:
            display_name = validate_string(
                data['display_name'], 'display_name',
                max_length=100, pattern=DISPLAY_NAME_PATTERN, required=False
            )
            if display_name:
                # Also update user document
                users_collection.update_one(
                    {'_id': g.current_user_id},
                    {'$set': {'display_name': display_name, 'updated_at': datetime.utcnow()}}
                )
                update_fields['display_name'] = display_name

        if 'social_links' in data:
            social_links = data['social_links']
            if not isinstance(social_links, dict):
                return jsonify({'error': 'social_links must be an object'}), 400
            allowed_social_keys = {'twitter', 'github', 'linkedin', 'website'}
            url_pattern = re.compile(r'^https?://[a-zA-Z0-9\-._~:/?#\[\]@!$&\'()*+,;=%]+$')
            validated_links = {}
            for key, value in social_links.items():
                if key not in allowed_social_keys:
                    continue
                if value and not url_pattern.match(str(value)[:2048]):
                    return jsonify({'error': f'Invalid URL for {key}'}), 400
                validated_links[key] = str(value)[:2048] if value else ''
            update_fields['social_links'] = validated_links

        if 'preferences' in data:
            prefs = data['preferences']
            if not isinstance(prefs, dict):
                return jsonify({'error': 'preferences must be an object'}), 400
            validated_prefs = {}
            if 'theme' in prefs:
                validated_prefs['theme'] = validate_enum(
                    prefs['theme'], {'light', 'dark'}, 'theme'
                )
            if 'notifications' in prefs:
                if not isinstance(prefs['notifications'], bool):
                    return jsonify({'error': 'notifications must be a boolean'}), 400
                validated_prefs['notifications'] = prefs['notifications']
            if validated_prefs:
                update_fields['preferences'] = validated_prefs

        if not update_fields:
            return jsonify({'error': 'No valid fields to update'}), 400

        update_fields['updated_at'] = datetime.utcnow()

        profiles_collection.update_one(
            {'user_id': g.current_user_id},
            {'$set': update_fields}
        )

        return jsonify({'message': 'Profile updated successfully'}), 200

    except ValueError as e:
        return jsonify({'error': str(e)}), 400
    except Exception as e:
        logger.error(f"Update profile error: {type(e).__name__}")
        return jsonify({'error': 'Internal server error'}), 500


