@app.route('/api/documents', methods=['POST'])
@require_auth
@require_role('editor', 'admin')
def create_document():
    """Create a new document."""
    try:
        data = request.get_json()
        if not data:
            return jsonify({'error': 'Request body is required'}), 400

        title = validate_string(data.get('title'), 'title', max_length=200)
        content = validate_string(data.get('content'), 'content', max_length=50000)
        category = validate_enum(
            data.get('category', 'article'), ALLOWED_DOCUMENT_CATEGORIES, 'category'
        )
        status = validate_enum(
            data.get('status', 'draft'), ALLOWED_DOCUMENT_STATUSES, 'status'
        )
        tags = validate_tags(data.get('tags', []))
        summary = validate_string(
            data.get('summary'), 'summary', max_length=500, required=False
        )

        doc = {
            'title': title,
            'content': content,
            'summary': summary or '',
            'category': category,
            'status': status,
            'tags': tags,
            'author_id': g.current_user_id,
            'author_username': g.current_user['username'],
            'created_at': datetime.utcnow(),
            'updated_at': datetime.utcnow(),
            'published_at': datetime.utcnow() if status == 'published' else None,
            'view_count': 0,
            'version': 1,
        }

        result = documents_collection.insert_one(doc)

        logger.info(f"Document created: {result.inserted_id} by {g.current_user['username']}")

        return jsonify({
            'message': 'Document created successfully',
            'document_id': str(result.inserted_id),
        }), 201

    except ValueError as e:
        return jsonify({'error': str(e)}), 400
    except Exception as e:
        logger.error(f"Create document error: {type(e).__name__}")
        return jsonify({'error': 'Internal server error'}), 500


@app.route('/api/documents/<doc_id>', methods=['GET'])
@require_auth
def get_document(doc_id):
    """Get a document by ID."""
    try:
        oid = validate_object_id(doc_id, 'document_id')

        doc = documents_collection.find_one({'_id': oid})
        if not doc:
            return jsonify({'error': 'Document not found'}), 404

        # Authorization: viewers can only see published documents
        if g.current_role == 'viewer' and doc['status'] != 'published':
            return jsonify({'error': 'Document not found'}), 404

        # Editors can see their own documents in any status
        if g.current_role == 'editor' and doc['author_id'] != g.current_user_id and doc['status'] != 'published':
            return jsonify({'error': 'Document not found'}), 404

        # Increment view count
        documents_collection.update_one(
            {'_id': oid},
            {'$inc': {'view_count': 1}}
        )

        doc['_id'] = str(doc['_id'])
        doc['author_id'] = str(doc['author_id'])
        if doc.get('created_at'):
            doc['created_at'] = doc['created_at'].isoformat()
        if doc.get('updated_at'):
            doc['updated_at'] = doc['updated_at'].isoformat()
        if doc.get('published_at'):
            doc['published_at'] = doc['published_at'].isoformat()

        return jsonify(doc), 200

    except ValueError as e:
        return jsonify({'error': str(e)}), 400
    except Exception as e:
        logger.error(f"Get document error: {type(e).__name__}")
        return jsonify({'error': 'Internal server error'}), 500


